		CtrlEnabled("e_posaprob_super"    ,false);

		//Evaluacion 360
		CtrlEnabled("e_show_360"        ,false);
		CtrlEnabled("e_preeval_360"     ,false);
		CtrlEnabled("e_evaluador_360"   ,false);
		CtrlEnabled("e_evaluado_360"    ,false);
		CtrlEnabled("e_supervisor_360"  ,false);
		CtrlEnabled("e_evaluador360_360",false);
		CtrlEnabled("e_aprobacion_360"  ,false);
		CtrlEnabled("e_posaprob_360"    ,false);

		//Comentarios
		CtrlEnabled("e_show_coment"        ,false);
		CtrlEnabled("e_preeval_coment"     ,false);
