		Ctrl("lbl_d_cus3").SetText("Parametro 3");
		Ctrl("lbl_d_cus4").SetText("Parametro 4");
		Ctrl("lbl_d_cus5").SetText("Parametro 5");
	} else
	{                
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("impl");                      

		if (rep=="")
		{           
			CtrlEnabled("l_mostrar_res", true);

			//Plantilla                      
			CtrlSetValue("e_show_show"        , false, "1");
			CtrlSetValue("e_preeval_show"     , false, "0");
			CtrlSetValue("e_evaluador_show"   , false, "1");
			CtrlSetValue("e_evaluado_show"    , false, "0");
