			CtrlSetValue("e_evaluador_360"   , false, "0");
			CtrlSetValue("e_evaluado_360"    , false, "0");
			CtrlSetValue("e_supervisor_360"  , false, "0");
			CtrlSetValue("e_evaluador360_360", false, "0");
			CtrlSetValue("e_aprobacion_360"  , false, "0");
