			CtrlSetValue("e_evaluado_edit"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_edit"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador360_edit", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_edit"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_edit"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux?true:false), "0");

			//Evaluador                
			l_aux=(rep.substr(1,1)=="E");
			CtrlSetValue("e_show_eval"        , (Ctrl("e_show_show"        ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_preeval_eval"     , (Ctrl("e_preeval_show"     ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador_eval"   , (Ctrl("e_evaluador_show"   ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluado_eval"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_eval"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador360_eval", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_eval"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_eval"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux?true:false), "0");

			//Autoevaluacion
			l_aux=(rep.substr(2,1)=="A");
			CtrlSetValue("e_show_auto"        , (Ctrl("e_show_show"        ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_preeval_auto"     , (Ctrl("e_preeval_show"     ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_evaluador_auto"   , (Ctrl("e_evaluador_show"   ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_evaluado_auto"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_supervisor_auto"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_evaluador360_auto", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_aprobacion_auto"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");
			CtrlSetValue("e_posaprob_auto"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux && l_eva2?true:false), "0");

			//Supervisor
			l_aux=(rep.substr(3,1)=="S");
			CtrlSetValue("e_show_super"        , (Ctrl("e_show_show"        ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_preeval_super"     , (Ctrl("e_preeval_show"     ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_evaluador_super"   , (Ctrl("e_evaluador_show"   ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_evaluado_super"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_supervisor_super"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_evaluador360_super", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_aprobacion_super"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");
			CtrlSetValue("e_posaprob_super"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux && l_eva3?true:false), "0");

			//Evaluacion 360
			l_aux=(rep.substr(6,1)=="3");
			CtrlSetValue("e_show_360"        , (Ctrl("e_show_show"        ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_preeval_360"     , (Ctrl("e_preeval_show"     ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_evaluador_360"   , (Ctrl("e_evaluador_show"   ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_evaluado_360"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_supervisor_360"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_evaluador360_360", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_aprobacion_360"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");
			CtrlSetValue("e_posaprob_360"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux && l_eva360?true:false), "0");

			//Comentarios
			l_aux=(rep.substr(4,1)=="C");
			CtrlSetValue("e_show_coment"        , (Ctrl("e_show_show"        ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_preeval_coment"     , (Ctrl("e_preeval_show"     ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador_coment"   , (Ctrl("e_evaluador_show"   ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluado_coment"    , (Ctrl("e_evaluado_show"    ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_supervisor_coment"  , (Ctrl("e_supervisor_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_evaluador360_coment", (Ctrl("e_evaluador360_show").GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_aprobacion_coment"  , (Ctrl("e_aprobacion_show"  ).GetXValue()=="1" && l_aux?true:false), "0");
			CtrlSetValue("e_posaprob_coment"    , (Ctrl("e_posaprob_show"    ).GetXValue()=="1" && l_aux?true:false), "0");
		}

		//Parametros         
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("param1"); Ctrl("lbl_d_cus1").SetText(rep==""?"Parametro 1":rep);
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("param2"); Ctrl("lbl_d_cus2").SetText(rep==""?"Parametro 2":rep);
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("param3"); Ctrl("lbl_d_cus3").SetText(rep==""?"Parametro 3":rep);
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("param4"); Ctrl("lbl_d_cus4").SetText(rep==""?"Parametro 4":rep);
		rep=pantXML.FindElement2("option","value",Ctrl("d_reporte").GetXValue()).GetAttr("param5"); Ctrl("lbl_d_cus5").SetText(rep==""?"Parametro 5":rep);
	}

	//Refresh 
	ChangeShow();
	ChangePreEval();
	ChangeEvaluador();
	ChangeEvaluado();
	ChangeSupervisor();
	ChangeAprobacion();
	ChangePosaprob();
	ChangeEvaluador360();
}      


function CtrlSetValue(Name, enabled, value)
{                
	var ct=Ctrl(Name);

	ct.SetEnabled(enabled);
	if (!enabled) ct.SetXValue(value);
}

function GetCalculateStatus(Name)
{
	var valor=0;      

	valor+=parseInt(Ctrl(Name+"_edit"  ).GetXValue(), 10)*1;
	valor+=parseInt(Ctrl(Name+"_eval"  ).GetXValue(), 10)*2;
	valor+=parseInt(Ctrl(Name+"_auto"  ).GetXValue(), 10)*8;
	valor+=parseInt(Ctrl(Name+"_super" ).GetXValue(), 10)*32;
	valor+=parseInt(Ctrl(Name+"_coment").GetXValue(), 10)*128;
	valor+=parseInt(Ctrl(Name+"_show"  ).GetXValue(), 10)*512;
	valor+=parseInt(Ctrl(Name+"_360"   ).GetXValue(), 10)*1024;
	return ""+valor;
}  


function ChangeShow() { Ctrl("e_show").SetXValue(GetCalculateStatus("e_show")); }
function ChangeShowShow() { EnabledControls(); Ctrl("e_show").SetXValue(GetCalculateStatus("e_show")); }

function ChangePreEval() { Ctrl("e_preeval").SetXValue(GetCalculateStatus("e_preeval")); }
function ChangePreEvalShow() { EnabledControls(); Ctrl("e_preeval").SetXValue(GetCalculateStatus("e_preeval")); }

function ChangeEvaluador() { Ctrl("e_evaluador").SetXValue(GetCalculateStatus("e_evaluador")); }
function ChangeEvaluadorShow() { EnabledControls(); Ctrl("e_evaluador").SetXValue(GetCalculateStatus("e_evaluador")); }

function ChangeEvaluado() { Ctrl("e_evaluado").SetXValue(GetCalculateStatus("e_evaluado")); }
function ChangeEvaluadoShow() { EnabledControls(); Ctrl("e_evaluado").SetXValue(GetCalculateStatus("e_evaluado")); }

function ChangeSupervisor() { Ctrl("e_supervisor").SetXValue(GetCalculateStatus("e_supervisor")); }
function ChangeSupervisorShow() { EnabledControls(); Ctrl("e_supervisor").SetXValue(GetCalculateStatus("e_supervisor")); }

function ChangeAprobacion() { Ctrl("e_aprobacion").SetXValue(GetCalculateStatus("e_aprobacion")); }
function ChangeAprobacionShow() { EnabledControls(); Ctrl("e_aprobacion").SetXValue(GetCalculateStatus("e_aprobacion")); }

function ChangePosaprob() { Ctrl("e_posaprob").SetXValue(GetCalculateStatus("e_posaprob")); }
function ChangePosaprobShow() { EnabledControls(); Ctrl("e_posaprob").SetXValue(GetCalculateStatus("e_posaprob")); }

function ChangeEvaluador360() { Ctrl("e_evaluador360").SetXValue(GetCalculateStatus("e_evaluador360")); }
function ChangeEvaluador360Show() { EnabledControls(); Ctrl("e_evaluador360").SetXValue(GetCalculateStatus("e_evaluador360")); }


function GetEvalEstado(Name, levAND, levDIV)
{                                               
	if (Ctrl(Name).GetXValue()=="") return "0";

	var value=Math.floor((parseInt(Ctrl(Name).GetXValue(),10) & levAND) / levDIV);
	return value.toString();
}


function PosOnLoad()
{
	if (Ctrl("main").GetLastDoc("d_reporte")!=null)
		pantXML=new NomadXML(Ctrl("main").GetLastDoc("d_reporte"));

	//Consulta
	Ctrl("e_show_show"        ).SetXValue(GetEvalEstado("e_show"        ,512,512));
	Ctrl("e_preeval_show"     ).SetXValue(GetEvalEstado("e_preeval"     ,512,512));
	Ctrl("e_evaluador_show"   ).SetXValue(GetEvalEstado("e_evaluador"   ,512,512));
	Ctrl("e_evaluado_show"    ).SetXValue(GetEvalEstado("e_evaluado"    ,512,512));
	Ctrl("e_supervisor_show"  ).SetXValue(GetEvalEstado("e_supervisor"  ,512,512));
	Ctrl("e_evaluador360_show").SetXValue(GetEvalEstado("e_evaluador360",512,512));
	Ctrl("e_aprobacion_show"  ).SetXValue(GetEvalEstado("e_aprobacion"  ,512,512));
	Ctrl("e_posaprob_show"    ).SetXValue(GetEvalEstado("e_posaprob"    ,512,512));

	//Editable
	Ctrl("e_show_edit"        ).SetXValue(GetEvalEstado("e_show"        ,1,1));
	Ctrl("e_preeval_edit"     ).SetXValue(GetEvalEstado("e_preeval"     ,1,1));
	Ctrl("e_evaluador_edit"   ).SetXValue(GetEvalEstado("e_evaluador"   ,1,1));
	Ctrl("e_evaluado_edit"    ).SetXValue(GetEvalEstado("e_evaluado"    ,1,1));
	Ctrl("e_supervisor_edit"  ).SetXValue(GetEvalEstado("e_supervisor"  ,1,1));
	Ctrl("e_evaluador360_edit").SetXValue(GetEvalEstado("e_evaluador360",1,1));
	Ctrl("e_aprobacion_edit"  ).SetXValue(GetEvalEstado("e_aprobacion"  ,1,1));
	Ctrl("e_posaprob_edit"    ).SetXValue(GetEvalEstado("e_posaprob"    ,1,1));

	//Evaluador
	Ctrl("e_show_eval"        ).SetXValue(GetEvalEstado("e_show"        ,6,2));
	Ctrl("e_preeval_eval"     ).SetXValue(GetEvalEstado("e_preeval"     ,6,2));
	Ctrl("e_evaluador_eval"   ).SetXValue(GetEvalEstado("e_evaluador"   ,6,2));
	Ctrl("e_evaluado_eval"    ).SetXValue(GetEvalEstado("e_evaluado"    ,6,2));
	Ctrl("e_supervisor_eval"  ).SetXValue(GetEvalEstado("e_supervisor"  ,6,2));
	Ctrl("e_evaluador360_eval").SetXValue(GetEvalEstado("e_evaluador360",6,2));
	Ctrl("e_aprobacion_eval"  ).SetXValue(GetEvalEstado("e_aprobacion"  ,6,2));
	Ctrl("e_posaprob_eval"    ).SetXValue(GetEvalEstado("e_posaprob"    ,6,2));

	//Autoevaluacion
	Ctrl("e_show_auto"        ).SetXValue(GetEvalEstado("e_show"        ,24,8));
	Ctrl("e_preeval_auto"     ).SetXValue(GetEvalEstado("e_preeval"     ,24,8));
	Ctrl("e_evaluador_auto"   ).SetXValue(GetEvalEstado("e_evaluador"   ,24,8));
